import Accordion from '@/components/Accordion';
import Technology from '@/types/Technology';
import { Terminal } from 'lucide-react';
import AccordionItems from './components/AccordionItems';
import Table from './components/Table';
import TableRow from './components/Table/TableRow';
import Form from '@/components/Form';
import Input from '../login/components/Input';

export default async function AdminPage() {
  async function fetchTechnologies() {
    const response = await fetch(`${process.env.API_URL}/technologies`, {
      cache: 'force-cache'
    });
    const data = await response.json();
    return data;
  }
  const data = await fetchTechnologies();
  const tecnologies: Technology[] = data.data;

  return (
    <>
      <section className="relative flex h-screen flex-col items-center py-6 text-white lg:p-16">
        <h1 className="mb-5 flex items-center gap-4">
          <span className="animate-pulse">
            <Terminal style={{ color: 'var(--color-primary)' }} size={40} />
          </span>
          OLÁ JOEL!
        </h1>
        <section className="w-full">
          <Table title="Tecnologias">
            <Accordion >
              <Form action={async (formData: FormData) => {
                // Add your form submission logic here
              }}>
                <Input name="technology" label="Nova Tecnologia" type="text" />
              </Form>
            </Accordion>
            {tecnologies.map((technology: Technology) => (
              <TableRow
                key={technology.id}
                content={technology.name}
                identifier={technology.id}
              />
            ))}
          </Table>
        </section>
      </section>
    </>
  );
}
