import TableButtons from './TableButtons';

interface TableRowProps {
  content: string;
  identifier: string;
}

export default function TableRow({ content, identifier }: TableRowProps) {
  return (
    <tr className="flex w-full justify-between py-2 border-b border-b-primary/10 items-center">
      <td className="text-xl">{content}</td>
      <TableButtons identifier={identifier} />
    </tr>
  );
}
